  409: /* Is this recovered BUI ok? */
  410: static inline bool
  411: xfs_bui_validate(
  412: 	struct xfs_mount		*mp,
  413: 	struct xfs_bui_log_item		*buip)
  414: {
  415: 	struct xfs_map_extent		*map;
  416: 
  417: 	/* Only one mapping operation per BUI... */
  418: 	if (buip->bui_format.bui_nextents != XFS_BUI_MAX_FAST_EXTENTS)
  419: 		return false;
  420: 
  421: 	map = &buip->bui_format.bui_extents[0];
  422: 
  423: 	if (map->me_flags & ~XFS_BMAP_EXTENT_FLAGS)
  424: 		return false;
  425: 
  426: 	switch (map->me_flags & XFS_BMAP_EXTENT_TYPE_MASK) {
  427: 	case XFS_BMAP_MAP:
  428: 	case XFS_BMAP_UNMAP:
  429: 		break;
  430: 	default:
  431: 		return false;
  432: 	}
  433: 
  434: 	if (!xfs_verify_ino(mp, map->me_owner))
  435: 		return false;
  436: 
  437: 	if (!xfs_verify_fileext(mp, map->me_startoff, map->me_len))
  438: 		return false;
  439: 
  440: 	if (map->me_flags & XFS_BMAP_EXTENT_REALTIME)
  441: 		return xfs_verify_rtbext(mp, map->me_startblock, map->me_len);
  442: 
  443: 	return xfs_verify_fsbext(mp, map->me_startblock, map->me_len);
  444: }
