  799: 	unsigned int		resblks;
  800: 	int			nmaps;
  801: 	bool			isrt = XFS_IS_REALTIME_INODE(ip);
  802: 	int			error;
  803: 
  804: 	resblks = XFS_EXTENTADD_SPACE_RES(mp, XFS_DATA_FORK);
  805: 	error = xfs_trans_alloc(mp, &M_RES(mp)->tr_write, resblks, 0,
  806: 			XFS_TRANS_RESERVE, &tp);
> 807: 	if (error)
  808: 		return error;
  809: 
  810: 	/*
  811: 	 * Lock the inode.  We have to ijoin without automatic unlock because
  812: 	 * the lead transaction is the refcountbt record deletion; the data
  813: 	 * fork update follows as a deferred log item.
  814: 	 */
  815: 	xfs_ilock(ip, XFS_ILOCK_EXCL);
  816: 	xfs_trans_ijoin(tp, ip, 0);
  817: 
  818: 	/*
  819: 	 * In case of racing, overlapping AIO writes no COW extents might be
  820: 	 * left by the time I/O completes for the loser of the race.  In that
  821: 	 * case we are done.
  822: 	 */
  823: 	if (!xfs_iext_lookup_extent(ip, ifp, *offset_fsb, &icur, &got) ||
  824: 	    got.br_startoff >= end_fsb) {
  825: 		*offset_fsb = end_fsb;
  826: 		goto out_cancel;
  827: 	}
  828: 
  829: 	/*
  830: 	 * Only remap real extents that contain data.  With AIO, speculative
  831: 	 * preallocations can leak into the range we are called upon, and we
  832: 	 * need to skip them.  Preserve @got for the eventual CoW fork
  833: 	 * deletion; from now on @del represents the mapping that we're
  834: 	 * actually remapping.
  835: 	 */
  836: 	while (!xfs_bmap_is_written_extent(&got)) {
  837: 		if (!xfs_iext_next_extent(ifp, &icur, &got) ||
  838: 		    got.br_startoff >= end_fsb) {
  839: 			*offset_fsb = end_fsb;
  840: 			goto out_cancel;
  841: 		}
  842: 	}
  843: 	del = got;
  844: 	xfs_trim_extent(&del, *offset_fsb, end_fsb - *offset_fsb);
  845: 
  846: 	error = xfs_iext_count_extend(tp, ip, XFS_DATA_FORK,
  847: 			XFS_IEXT_REFLINK_END_COW_CNT);
