  851: 	/* Grab the corresponding mapping in the data fork. */
  852: 	nmaps = 1;
  853: 	error = xfs_bmapi_read(ip, del.br_startoff, del.br_blockcount, &data,
  854: 			&nmaps, 0);
  855: 	if (error)
  856: 		goto out_cancel;
  857: 
  858: 	/* We can only remap the smaller of the two extent sizes. */
  859: 	data.br_blockcount = min(data.br_blockcount, del.br_blockcount);
  860: 	del.br_blockcount = data.br_blockcount;
