  865: 	if (xfs_bmap_is_real_extent(&data)) {
  866: 		/*
  867: 		 * If the extent we're remapping is backed by storage (written
  868: 		 * or not), unmap the extent and drop its refcount.
  869: 		 */
  870: 		xfs_bmap_unmap_extent(tp, ip, XFS_DATA_FORK, &data);
  871: 		xfs_refcount_decrease_extent(tp, isrt, &data);
  872: 		xfs_reflink_update_quota(tp, ip, false, -data.br_blockcount);
  873: 	} else if (data.br_startblock == DELAYSTARTBLOCK) {
  874: 		int		done;
  875: 
  876: 		/*
  877: 		 * If the extent we're remapping is a delalloc reservation,
  878: 		 * we can use the regular bunmapi function to release the
  879: 		 * incore state.  Dropping the delalloc reservation takes care
  880: 		 * of the quota reservation for us.
  881: 		 */
  882: 		error = xfs_bunmapi(NULL, ip, data.br_startoff,
  883: 				data.br_blockcount, 0, 1, &done);
  884: 		if (error)
  885: 			goto out_cancel;
  886: 		ASSERT(done);
  887: 	}

