   63: 	/*
   64: 	 * Loop over logs of extent sizes.
   65: 	 */
   66: 	for (log = high; log >= low; log--) {
   67: 		/*
   68: 		 * Get one summary datum.
   69: 		 */
   70: 		error = xfs_rtget_summary(args, log, bbno, &sum);
   71: 		if (error) {
   72: 			return error;
   73: 		}
   74: 		/*
   75: 		 * If there are any, return success.
   76: 		 */
   77: 		if (sum) {
   78: 			*maxlog = log;
   79: 			goto out;
